let teams = DATA.teams;
let rules = DATA.rules;
const fmt = v => (v === null || v === undefined || v === "" ? "-" : String(v).replace('.', ','));
const n = v => Number(v || 0);
const fidoUsed = t => Math.max(0, rules.maxFido - n(t.fidoResidual));
const stadiumMaint = lvl => rules.stadiumMaintenance[String(lvl ?? 0)] ?? 0;
const stadiumBonus = lvl => rules.stadiumBonus[String(lvl ?? 0)] ?? 0;
const roleShort = role => ({Portiere:'P', Difensore:'D', Centrocampista:'C', Attaccante:'A'}[role] || role);
