const isLoanInStatus = status => {
  const s = String(status || "").toUpperCase().replace(/[\s-]+/g, "_");
  return ["PRESTITO_IN", "PRESTITO_ENTRATA", "IN_PRESTITO"].includes(s);
};


const SKL_LIVE_CACHE_KEY = "skl_live_dashboard_data_v1";
const SKL_API_URL = "https://script.google.com/macros/s/AKfycbztJtSp_-LBCJe7wTlp7_nsGO4gjlEkDvwDuV8LaHKiE-b_kl8p15AL5xq__HCaJlsq/exec";

function readLiveDataCache(){
  try {
    const raw = localStorage.getItem(SKL_LIVE_CACHE_KEY);
    if(!raw) return null;
    const parsed = JSON.parse(raw);
    return parsed && Array.isArray(parsed.teams) && parsed.rules ? parsed : null;
  } catch (error) {
    console.warn("Cache live non leggibile", error);
    return null;
  }
}

function writeLiveDataCache(data){
  try {
    localStorage.setItem(SKL_LIVE_CACHE_KEY, JSON.stringify(data));
  } catch (error) {
    console.warn("Impossibile salvare la cache live", error);
  }
}

function setInitialLoading(isLoading, message="Caricamento dati aggiornati…"){
  const overlay = document.getElementById("initialLoading");
  const label = document.getElementById("initialLoadingText");
  if(label) label.textContent = message;
  if(!overlay) return;
  overlay.hidden = !isLoading;
  document.body.classList.toggle("is-initial-loading", isLoading);
}


function loadDataFromAppsScript() {
  return new Promise((resolve, reject) => {
    const callbackName = "sklCallback_" + Date.now();
    const script = document.createElement("script");

    const timeout = setTimeout(() => {
      delete window[callbackName];
      if (script.parentNode) script.remove();
      reject(new Error("Timeout caricamento dati da Apps Script"));
    }, 8000);

    window[callbackName] = data => {
      clearTimeout(timeout);
      resolve(data);
      delete window[callbackName];
      if (script.parentNode) script.remove();
    };

    script.src = `${SKL_API_URL}?callback=${callbackName}&t=${Date.now()}`;
    script.onerror = () => {
      clearTimeout(timeout);
      delete window[callbackName];
      reject(new Error("Impossibile caricare dati da Apps Script"));
    };

    document.body.appendChild(script);
  });
}

let autoRefreshTimer = null;
let isRefreshingData = false;

async function refreshDashboardData({silent=false} = {}) {
  if (isRefreshingData) return;
  isRefreshingData = true;

  const selectedTeamId = document.getElementById('teamSelect')?.value || teams[0]?.id;

  try {
    DATA = await loadDataFromAppsScript();
    writeLiveDataCache(DATA);
    window.SKL_DATA = DATA;
    teams = DATA.teams;
    rules = DATA.rules;

    renderRankings();
    renderAlerts();
    renderTeamsTable();
    renderSelector();
    renderRolesTable();
    renderMarketTable();
    renderHallOfFame();
    loadSerieANews();

    const teamToRender = teams.some(t => t.id === selectedTeamId) ? selectedTeamId : teams[0]?.id;
    if (teamToRender) renderTeam(teamToRender);

    const lastUpdateEl = document.getElementById('lastUpdate');
    if (lastUpdateEl) lastUpdateEl.textContent = DATA.updatedFrom;

    if (!silent) console.log("Dati live aggiornati da Apps Script", DATA);
  } catch (error) {
    console.warn("Aggiornamento dati fallito. Mantengo i dati correnti.", error);
  } finally {
    isRefreshingData = false;
  }
}

async function bootstrap() {
  const cachedLiveData = readLiveDataCache();
  setInitialLoading(true, cachedLiveData ? "Aggiornamento dati in corso…" : "Caricamento dati aggiornati…");

  let initialData = null;

  try {
    initialData = await loadDataFromAppsScript();
    writeLiveDataCache(initialData);
    console.log("Dati live caricati all'avvio", initialData);
  } catch (error) {
    console.warn("Caricamento live iniziale fallito", error);
    initialData = cachedLiveData || window.SKL_DATA;
  }

  DATA = initialData;
  window.SKL_DATA = DATA;
  teams = DATA.teams;
  rules = DATA.rules;

  init();
  loadSerieANews();
  setInitialLoading(false);

  if (autoRefreshTimer) clearInterval(autoRefreshTimer);
  autoRefreshTimer = setInterval(() => {
    refreshDashboardData({silent:true});
  }, 15000);
}

