let currentView = "home";

function setDrawerOpen(open){
  const drawer = document.getElementById("sideDrawer");
  const backdrop = document.getElementById("drawerBackdrop");
  const toggle = document.getElementById("menuToggle");
  if(!drawer || !backdrop || !toggle) return;

  drawer.classList.toggle("is-open", open);
  backdrop.hidden = !open;
  document.body.classList.toggle("drawer-open", open);
  drawer.setAttribute("aria-hidden", String(!open));
  toggle.setAttribute("aria-expanded", String(open));
}

function showView(view, {updateHash = true} = {}){
  const allowed = ["home", "teams", "market", "honours"];
  currentView = allowed.includes(view) ? view : "home";

  document.body.classList.remove("view-home", "view-teams", "view-market", "view-honours");
  document.body.classList.add(`view-${currentView}`);

  document.querySelectorAll("[data-page]").forEach(el => {
    el.hidden = el.dataset.page !== currentView;
  });

  document.querySelectorAll(".drawer-link[data-view]").forEach(button => {
    const active = button.dataset.view === currentView;
    button.classList.toggle("is-active", active);
    button.setAttribute("aria-current", active ? "page" : "false");
  });

  setDrawerOpen(false);
  window.scrollTo({top:0, behavior:"smooth"});
  if(updateHash) history.replaceState(null, "", `#${currentView}`);
}

function setupDrawerNavigation(){
  if(document.body.dataset.drawerReady === "true") return;
  document.body.dataset.drawerReady = "true";

  document.getElementById("menuToggle")?.addEventListener("click", () => setDrawerOpen(true));
  document.getElementById("menuClose")?.addEventListener("click", () => setDrawerOpen(false));
  document.getElementById("drawerBackdrop")?.addEventListener("click", () => setDrawerOpen(false));

  document.querySelectorAll(".drawer-link[data-view]").forEach(button => {
    button.addEventListener("click", () => showView(button.dataset.view));
  });
  document.querySelectorAll("[data-route]").forEach(link => {
    link.addEventListener("click", event => {
      event.preventDefault();
      showView(link.dataset.route);
    });
  });

  document.addEventListener("keydown", event => {
    if(event.key === "Escape") setDrawerOpen(false);
  });

  const hashView = location.hash.replace("#", "");
  showView(["home", "teams", "market", "honours"].includes(hashView) ? hashView : "home", {updateHash:false});
}

function init(){
  const lastUpdate = document.getElementById('lastUpdate');
  if(lastUpdate) lastUpdate.textContent = DATA.updatedFrom;
  renderRankings(); renderAlerts(); renderTeamsTable(); renderSelector(); renderTeam(teams[0].id); renderRolesTable(); renderMarketTable(); renderHallOfFame();
  setupDrawerNavigation();
}
function renderRankings(){
  const sorted=[...teams].sort((a,b)=>n(b.saldo)-n(a.saldo));
  const max=Math.max(...sorted.map(t=>n(t.saldo)),1);
  document.getElementById('saldoRanking').innerHTML=sorted.map((t,i)=>`<div class="rank-row"><b>${i+1}</b><div>${teamLabel(t.id, t.name)}<div class="bar"><span style="width:${(n(t.saldo)/max)*100}%"></span></div></div><strong>${fmt(t.saldo)}</strong></div>`).join('');
}
function getTeamAlerts(t){
  const alerts=[]; const count=n(t.playersCountSummary ?? t.playersCountParsed); const pg=n(t.roleCounts?.Portiere);
  if(n(t.saldo)===0) alerts.push(['danger','Saldo a 0: attenzione a nuove uscite o operazioni.']);
  if(fidoUsed(t)>0) alerts.push(['warn',`Fido usato: ${fidoUsed(t)} / ${rules.maxFido}.`]);
  if(count<rules.minPlayers) alerts.push(['danger',`Rosa sotto il minimo: ${count}/${rules.minPlayers}.`]);
  if(count>rules.maxPlayers) alerts.push(['danger',`Rosa sopra il massimo: ${count}/${rules.maxPlayers}.`]);
  if(pg>rules.maxGoalkeepers) alerts.push(['danger',`Troppi portieri nel foglio rosa: ${pg}/${rules.maxGoalkeepers}.`]);
  return alerts;
}
function renderAlerts(){
  const alertsEl = document.getElementById('alertsList');
  if(!alertsEl) return;
  const all=[]; teams.forEach(t=>getTeamAlerts(t).forEach(a=>all.push([t.name,...a])));
  alertsEl.innerHTML = all.length ? all.map(a=>`<div class="alert ${a[1]==='danger'?'danger':''}">${teamLabel(teamIdByName[a[0]], a[0], 'xs')}<br>${a[2]}</div>`).join('') : '<div class="alert ok">Nessun alert rilevante.</div>';
}
function renderTeamsTable(){
  const tableEl = document.getElementById('teamsTable');
  if(!tableEl) return;
  const rows=teams.map(t=>`<tr><td><strong>${t.name}</strong><br><small class="muted">${t.management}</small></td><td>${t.sponsor||'-'}</td><td class="num">${fmt(t.saldo)}</td><td class="num">${fmt(t.fidoResidual)}</td><td class="num">${fidoUsed(t)}</td><td class="num">${t.playersCountSummary ?? t.playersCountParsed}</td><td class="num">${t.stadiumLevel}</td><td class="num">${fmt(t.stadiumIncome)}</td><td>${badgeFor(t)}</td></tr>`).join('');
  tableEl.innerHTML=`<thead><tr><th>Squadra</th><th>Sponsor</th><th class="num">Saldo</th><th class="num">Fido residuo</th><th class="num">Fido usato</th><th class="num">Calciatori</th><th class="num">Stadio</th><th class="num">Introiti ottenuti</th><th>Stato</th></tr></thead><tbody>${rows}</tbody>`;
}
function badgeFor(t){ const a=getTeamAlerts(t); if(a.some(x=>x[0]==='danger')) return '<span class="pill bad">critico</span>'; if(a.length) return '<span class="pill warn">da controllare</span>'; return '<span class="pill good">ok</span>'; }
function renderSelector(){
  const sel=document.getElementById('teamSelect'); const current=sel.value || teams[0]?.id; sel.innerHTML=teams.map(t=>`<option value="${t.id}">${t.name}</option>`).join(''); if(teams.some(t=>t.id===current)) sel.value=current; sel.onchange=e=>renderTeam(e.target.value);
}

function marketBucket(m){
  const type = String(m.type || '').toLowerCase();
  if(type.includes('prestito')) return 'prestiti';
  if(type.includes('svincolo')) return 'svincoli';
  if(type.includes('acquisto')) return 'acquisti';
  return 'altri';
}
function marketBucketLabel(key){
  return ({acquisti:'Acquisti', prestiti:'Prestiti', svincoli:'Svincoli', altri:'Altri movimenti'})[key] || key;
}

function isNoiseMarketItem(m){
  const player = String(m.player || '').trim().toUpperCase();
  const details = String(m.details || '').trim().toUpperCase();
  const type = String(m.type || '').trim().toUpperCase();
  const amount = Number(m.amount || 0);

  const blockedExact = new Set([
    'MOVIMENTO','GIOCATORE','CONDIZIONI','POSIZIONE','LIVELLO','XTIE FUORI CASA',
    'GUADAGNI:','PREMI','COMPETIZIONE','NOTE','CLAUSOLE E NOTE CONTRATTUALI',
    'STADIO "NON SOLO CAFFÈ"','STADIO NON SOLO CAFFÈ'
  ]);

  if(blockedExact.has(player) || blockedExact.has(details)) return true;

  const combined = `${player} ${details} ${type}`.replace(/\s+/g, ' ').trim();
  const blockedContains = [
    'CLAUSOLE E NOTE CONTRATTUALI',
    'STADIO NON SOLO CAFFÈ',
    'GIOCATORE COSTO FISSO TIPO CLAUSOLA NOTE',
    'LIVELLO XTIE FUORI CASA COSTO GESTIONE FATTORE CAMPO',
    'COMPETIZIONE PREMIO'
  ];
  if(blockedContains.some(token => combined.includes(token))) return true;

  if(player === '-' && !details && !type) return true;
  if(player === '-' && amount === 0 && details === '-') return true;

  return false;
}
function cleanMarketItems(items){
  return (items || []).filter(m => !isNoiseMarketItem(m));
}

function isDateLike(value){
  return /^\d{2}\/\d{2}\/\d{4}$/.test(String(value || '').trim());
}

function normalizeLoanKey(value){
  return String(value || '')
    .trim()
    .toUpperCase()
    .normalize('NFD')
    .replace(/[̀-ͯ]/g, '')
    .replace(/[^A-Z0-9]+/g, ' ')
    .trim();
}

function buildLoanNotesMap(items){
  const map = new Map();
  (items || []).forEach(row => {
    const type = String(row.type || '').trim();
    const rawKey = String(row.date || '').trim();
    if(isDateLike(rawKey)) return;
    if(!type.toLowerCase().includes('prestito')) return;
    const key = normalizeLoanKey(rawKey);
    if(!key) return;
    map.set(key, {
      contractType: type,
      formula: String(row.player || '').trim(),
      fixedCost: String(row.otherTeam || '').trim(),
      note: String(row.details || '').trim()
    });
  });
  return map;
}

function loanDirectionInfo(details, currentTeamName, otherTeamName){
  const raw = String(details || '').trim();
  const normalized = raw.toLowerCase();
  const current = currentTeamName || 'Squadra attuale';
  const other = otherTeamName && otherTeamName !== '-' ? otherTeamName : 'Altra squadra';
  if(normalized.includes('entrata')){
    return {
      label:'In entrata',
      from:other,
      to:current,
      badgeClass:'incoming'
    };
  }
  if(normalized.includes('uscita')){
    return {
      label:'In uscita',
      from:current,
      to:other,
      badgeClass:'outgoing'
    };
  }
  return {
    label: raw || 'Prestito',
    from:current,
    to:other,
    badgeClass:'neutral'
  };
}

function renderLoanMarketItem(m, team, notesMap){
  const amount = Number(m.amount || 0);
  const amountClass = amount > 0 ? 'plus' : amount < 0 ? 'minus' : 'zero';
  const signed = amount > 0 ? `+${fmt(m.amount)}` : fmt(m.amount);
  const note = notesMap.get(normalizeLoanKey(m.player));
  const direction = loanDirectionInfo(m.details, team.name, m.otherTeam);
  const formula = note && note.formula && note.formula !== '-' ? note.formula : '';
  const fixedCost = note && note.fixedCost && note.fixedCost !== '-' ? `${note.fixedCost} fm` : '';
  const contractType = note && note.contractType ? note.contractType : 'Prestito';
  const noteText = note && note.note && note.note !== '-' ? note.note : '';
  const hasDetails = Boolean(formula || fixedCost || noteText || contractType);

  return `
    <div class="loan-row">
      <div class="loan-row__main">
        <div class="loan-row__identity">
          <strong>${escapeHtml(m.player || 'Prestito')}</strong>
          <small>${escapeHtml(m.date || '-')}</small>
        </div>
        <div class="loan-row__route" aria-label="${escapeHtml(direction.from)} verso ${escapeHtml(direction.to)}">
          <span>${escapeHtml(direction.from)}</span>
          <b aria-hidden="true">→</b>
          <span>${escapeHtml(direction.to)}</span>
        </div>
        <span class="loan-badge loan-badge--${direction.badgeClass}">${direction.label}</span>
        <div class="market-amount ${amountClass}">${signed} fm</div>
      </div>
      ${hasDetails ? `
        <details class="loan-details">
          <summary>Dettagli prestito</summary>
          <div class="loan-details__content">
            <span>${escapeHtml(contractType)}</span>
            ${formula ? `<span>${escapeHtml(formula)}</span>` : ''}
            ${fixedCost ? `<span>Costo fisso ${escapeHtml(fixedCost)}</span>` : ''}
            ${noteText ? `<p>${escapeHtml(noteText)}</p>` : ''}
          </div>
        </details>
      ` : ''}
    </div>
  `;
}

function extractCompetitionPrizes(items){
  const rows = items || [];
  const start = rows.findIndex(m => String(m.date || '').trim().toUpperCase() === 'PREMI');
  if(start === -1) return [];
  const prizes = [];
  for(let i = start + 1; i < rows.length; i++){
    const row = rows[i] || {};
    const competition = String(row.date || '').trim();
    const competitionUpper = competition.toUpperCase();
    if(!competition || competitionUpper === 'COMPETIZIONE') continue;
    if(/^\d{2}\/\d{2}\/\d{4}$/.test(competition)) break;
    const position = String(row.player || '').trim();
    const prize = String(row.otherTeam || row.details || '').trim();
    if(position){
      prizes.push({ competition, position, prize });
    }
  }
  return prizes;
}
function positionRank(value){
  const match = String(value || "").match(/\d+/);
  return match ? Number(match[0]) : 99;
}

function normalizeCompetitionName(value){
  return String(value || "")
    .trim()
    .toUpperCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^A-Z0-9]+/g, " ")
    .trim();
}

function competitionKey(value){
  const name = normalizeCompetitionName(value);
  if(name.includes("WINTER")) return "winter-cup";
  if(name.includes("KINGS") && name.includes("TROPHY")) return "kings-trophy";
  if(name.includes("CAMPIONATO") || name.includes("LEAGUE")) return "campionato";
  return "";
}

function renderHallOfFame(){
  const root = document.getElementById("hallOfFame");
  if(!root) return;

  const competitions = [
    { key:"campionato", label:"Campionato", icon:"★" },
    { key:"winter-cup", label:"Winter Cup", icon:"❄" },
    { key:"kings-trophy", label:"Kings Trophy", icon:"♛" }
  ];

  const wins = Object.fromEntries(competitions.map(item => [item.key, new Map()]));

  teams.forEach(team => {
    extractCompetitionPrizes(team.market).forEach(entry => {
      const key = competitionKey(entry.competition);
      if(!key || positionRank(entry.position) !== 1) return;
      const teamWins = wins[key];
      teamWins.set(team.id, {
        team,
        count:(teamWins.get(team.id)?.count || 0) + 1
      });
    });
  });

  root.innerHTML = competitions.map(competition => {
    const champions = [...wins[competition.key].values()]
      .sort((a,b) => b.count - a.count || a.team.name.localeCompare(b.team.name, "it"));

    return `<article class="honours-card honours-card--summary panel">
      <div class="honours-card__top">
        <div class="honours-trophy" aria-hidden="true">${competition.icon}</div>
        <div><p class="eyebrow">Trofei conquistati</p><h3>${competition.label}</h3></div>
      </div>
      <div class="honours-count-list">
        ${champions.length ? champions.map(entry => `
          <div class="honours-count-row">
            <div class="honours-count-team">
              ${teamLogo(entry.team.id) ? `<img class="team-logo honours-winner__logo" src="${teamLogo(entry.team.id)}" alt="">` : ''}
              <div><strong>${escapeHtml(entry.team.name)}</strong><small>${escapeHtml(entry.team.management || '')}</small></div>
            </div>
            <div class="honours-count"><strong>${entry.count}</strong><span>${entry.count === 1 ? 'trionfo' : 'trionfi'}</span></div>
          </div>
        `).join('') : `<div class="honours-empty"><strong>0</strong><span>trionfi</span></div>`}
      </div>
    </article>`;
  }).join('');
}

function getStadiumIncomeBreakdown(team){
  const rows = team.market || [];
  const gainsRow = rows.find(row =>
    String(row.details || '').trim().toUpperCase() === 'GUADAGNI:'
  );

  const drawsIncome = Number(gainsRow?.amount || 0);
  const totalIncome = Number(team.stadiumIncome || 0);
  const winsIncome = Math.max(0, totalIncome - drawsIncome);

  return {
    drawsIncome,
    winsIncome,
    totalIncome
  };
}

function prizeAmount(value){
  const raw = String(value ?? '').trim();
  if(!raw || raw === '-') return 0;
  const normalized = raw
    .replace(/[^0-9,.-]/g, '')
    .replace(/\./g, '')
    .replace(',', '.');
  const parsed = Number(normalized);
  return Number.isFinite(parsed) ? parsed : 0;
}

