function renderRolesTable(){
  const rows=teams.map(t=>`<tr><td>${teamLabel(t.id, t.name)}</td><td class="num">${n(t.roleCounts.Portiere)}</td><td class="num">${n(t.roleCounts.Difensore)}</td><td class="num">${n(t.roleCounts.Centrocampista)}</td><td class="num">${n(t.roleCounts.Attaccante)}</td><td class="num">${t.playersCountParsed}</td><td class="num">${t.playersCountSummary ?? '-'}</td></tr>`).join('');
  document.getElementById('rolesTable').innerHTML=`<thead><tr><th>Squadra</th><th class="num">P</th><th class="num">D</th><th class="num">C</th><th class="num">A</th><th class="num">Righe rosa</th><th class="num">Riepilogo</th></tr></thead><tbody>${rows}</tbody>`;
}
function parseDateIT(s){ if(!s) return 0; const [d,m,y]=s.split('/').map(Number); return new Date(y,m-1,d).getTime()||0; }
function normalizeMarketText(value){
  return String(value || "")
    .toUpperCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^A-Z0-9]+/g, " ")
    .trim();
}

function resolveMarketTeam(value){
  const raw = normalizeMarketText(value);
  if(!raw || raw === "-") return null;

  const aliases = {
    "AURELIANA":"avreliana",
    "AVRELIANA":"avreliana",
    "TNT":"tnt_legacy",
    "TNT LEGACY":"tnt_legacy",
    "GISA":"gisa_saviano",
    "GI SA":"gisa_saviano",
    "GISA SAVIANO":"gisa_saviano",
    "PSG":"fc_parco_s_giovanni",
    "PARCO S GIO":"fc_parco_s_giovanni",
    "PARCO S GIOVANNI":"fc_parco_s_giovanni",
    "FC PARCO S GIOVANNI":"fc_parco_s_giovanni",
    "PASTA NOCI":"la_pasta_con_le_noci",
    "LA PASTA CON LE NOCI":"la_pasta_con_le_noci",
    "ONE PIECE":"fc_one_piece",
    "FC ONE PIECE":"fc_one_piece",
    "LUDO":"ludopatykos",
    "LUDOPATYKOS":"ludopatykos",
    "HYDRA":"hydra_saviano",
    "HYDRA SAVIANO":"hydra_saviano",
    "RIONE SANT ERASMO":"rione_sant_erasmo",
    "RIONE SANT ERASMO":"rione_sant_erasmo",
    "TIGERS":"tigers_saviano",
    "TIGERS SAVIANO":"tigers_saviano"
  };

  const aliasId = aliases[raw];
  if(aliasId) return teams.find(t => t.id === aliasId) || null;

  return teams.find(t => {
    const name = normalizeMarketText(t.name);
    return name === raw || name.includes(raw) || raw.includes(name);
  }) || null;
}

function findMarketPlayer(playerName){
  const key = normalizeMarketText(playerName).replace(/\s+/g, "");
  for(const team of teams){
    const player = (team.roster || []).find(p =>
      normalizeMarketText(p.name).replace(/\s+/g, "") === key
    );
    if(player) return player;
  }
  return null;
}

function getTransferClauses(playerName){
  const playerKey = normalizeMarketText(playerName).replace(/\s+/g, "");
  const clauses = [];
  teams.forEach(team => {
    (team.market || []).forEach(row => {
      const rowKey = normalizeMarketText(row.date).replace(/\s+/g, "");
      const type = normalizeMarketText(row.type);
      if(rowKey === playerKey && type.includes("PRESTITO")){
        clauses.push({
          type: row.type || "Prestito",
          fixed: row.otherTeam,
          details: row.details
        });
      }
    });
  });
  return clauses[0] || null;
}

function buildPlayerTransfers(){
  const grouped = new Map();
  const datePattern = /^\d{2}\/\d{2}\/\d{4}$/;

  teams.forEach(team => {
    cleanMarketItems(team.market).forEach(row => {
      const type = normalizeMarketText(row.type);
      if(!datePattern.test(String(row.date || ""))) return;
      if(!type.includes("PRESTITO") && !type.includes("ACQUISTO")) return;
      if(!row.player || row.player === "-") return;

      const counterpart = resolveMarketTeam(row.otherTeam);
      if(!counterpart || counterpart.id === team.id) return;

      const key = `${row.date}|${normalizeMarketText(row.player).replace(/\s+/g, "")}`;
      if(!grouped.has(key)) grouped.set(key, []);
      grouped.get(key).push({ ...row, ownerTeam:team, counterpart });
    });
  });

  const transfers = [];
  grouped.forEach(records => {
    const first = records[0];
    let source = null;
    let destination = null;

    const outgoing = records.find(r => normalizeMarketText(r.details).includes("USCITA"));
    const incoming = records.find(r => normalizeMarketText(r.details).includes("ENTRATA"));

    if(outgoing) source = outgoing.ownerTeam;
    if(incoming) destination = incoming.ownerTeam;

    if(!source && incoming) source = incoming.counterpart;
    if(!destination && outgoing) destination = outgoing.counterpart;

    if(!source){
      const positive = records.find(r => Number(r.amount) > 0);
      if(positive) source = positive.ownerTeam;
    }
    if(!destination){
      const negative = records.find(r => Number(r.amount) < 0);
      if(negative) destination = negative.ownerTeam;
    }

    const involved = [...new Map(
      records.flatMap(r => [r.ownerTeam, r.counterpart]).map(t => [t.id, t])
    ).values()];

    if(!source && involved.length) source = involved[0];
    if(!destination) destination = involved.find(t => t.id !== source?.id) || null;
    if(!source || !destination || source.id === destination.id) return;

    const accountRows = records.map(r => ({
      team:r.ownerTeam,
      amount:r.amount
    }));

    transfers.push({
      date:first.date,
      player:first.player,
      type:first.type || "Trasferimento",
      source,
      destination,
      accountRows,
      clauses:getTransferClauses(first.player)
    });
  });

  return transfers.sort((a,b) => parseDateIT(b.date) - parseDateIT(a.date));
}

function renderTransferTeam(team, side){
  const logo = teamLogo(team.id);
  return `<div class="transfer-team transfer-team--${side}">
    ${logo ? `<img src="${logo}" alt="" class="transfer-team__logo">` : ""}
    <strong>${escapeHtml(team.name)}</strong>
  </div>`;
}

function renderMarketTable(){
  const host = document.getElementById("marketTable");
  if(!host) return;

  const transfers = buildPlayerTransfers();
  if(!transfers.length){
    host.innerHTML = '<div class="panel"><p class="muted">Nessun trasferimento tra squadre registrato.</p></div>';
    return;
  }

  host.innerHTML = transfers.map(transfer => {
    const player = findMarketPlayer(transfer.player);
    const photo = player?.playerPhoto || "";
    const initials = String(transfer.player || "?")
      .split(/\s+/)
      .map(part => part[0])
      .join("")
      .slice(0,2)
      .toUpperCase();

    const accounting = transfer.accountRows
      .filter(row => row.amount !== null && row.amount !== undefined && row.amount !== "")
      .map(row => `<span>${escapeHtml(row.team.name)} <b>${Number(row.amount) > 0 ? "+" : ""}${fmt(row.amount)} fm</b></span>`)
      .join("");

    const clauseHtml = transfer.clauses
      ? `<div class="transfer-card__clause">
          <span class="transfer-detail-label">Formula</span>
          <strong>${escapeHtml(transfer.clauses.type)}</strong>
          ${transfer.clauses.fixed && transfer.clauses.fixed !== "-" ? `<span>Fisso: ${escapeHtml(transfer.clauses.fixed)} fm</span>` : ""}
          ${transfer.clauses.details && transfer.clauses.details !== "-" ? `<span>${escapeHtml(transfer.clauses.details)}</span>` : ""}
        </div>`
      : "";

    const detailsHtml = `
      ${clauseHtml}
      ${accounting ? `<div class="transfer-card__accounting"><span class="transfer-detail-label">Movimenti contabili</span>${accounting}</div>` : ""}
    `.trim();

    return `<article class="transfer-card">
      <div class="transfer-card__topline">
        <time>${escapeHtml(transfer.date)}</time>
        <span class="transfer-kind">${escapeHtml(transfer.type)}</span>
      </div>

      <div class="transfer-route">
        ${renderTransferTeam(transfer.source, "source")}
        <div class="transfer-player">
          <div class="transfer-player__avatar">
            ${photo ? `<img src="${photo}" alt="${escapeHtml(transfer.player)}">` : `<span>${initials}</span>`}
          </div>
          <strong>${escapeHtml(transfer.player)}</strong>
          <span class="transfer-arrow" aria-label="si trasferisce verso">→</span>
        </div>
        ${renderTransferTeam(transfer.destination, "destination")}
      </div>

      ${detailsHtml ? `
      <details class="transfer-details">
        <summary>Dettagli operazione</summary>
        <div class="transfer-details__content">${detailsHtml}</div>
      </details>` : ""}
    </article>`;
  }).join("");
}

function escapeHtml(value){
  return String(value ?? "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}

function fallbackNews(){
  return [
    {title:"Gazzetta Serie A", text:"notizie non disponibili in questo momento"},
    {title:"SKL Manager", text:"dati lega aggiornati automaticamente ogni 15 secondi"}
  ];
}

function loadSerieANews(){
  const items = Array.isArray(DATA?.news) && DATA.news.length ? DATA.news : fallbackNews();
  renderNewsTicker(items.slice(0, 8));
}

function renderNewsTicker(items){
  const track = document.getElementById("newsTickerTrack");
  if(!track) return;

  const content = items.map(item => {
    const text = item.text ? `: ${item.text}` : "";
    return `<span><strong>${escapeHtml(item.title)}</strong>${escapeHtml(text)}</span>`;
  }).join("");

  track.innerHTML = content + content;
}

